DROP DATABASE IF EXISTS curriculum101;
CREATE DATABASE IF NOT EXISTS curriculum101;

USE curriculum101;

CREATE TABLE Instructors (
	instructorID  INT,
    title		NVARCHAR(20)	NOT NULL,
    firstName 	NVARCHAR(30)	NOT NULL,
    lastName	NVARCHAR(30)	NOT NULL,
    gender		CHAR(1)			NOT NULL,
	CONSTRAINT PK_instructor PRIMARY KEY (instructorID)
);


CREATE TABLE CourseTypes (
	type_code  CHAR(4),
	course_type	NVARCHAR(20) NOT NULL, 
	CONSTRAINT PK_coursetype PRIMARY KEY (type_code)
);

CREATE TABLE Areas (
	course_area  		CHAR(4),
	area_description	NVARCHAR(40) NOT NULL, 
	CONSTRAINT PK_coursearea PRIMARY KEY (course_area)
);

CREATE TABLE Programs (
	program_code 	CHAR(4),
	prog_level		NVARCHAR(40) 	NOT NULL, 
    degree			NVARCHAR(40),
    major			NVARCHAR(40),
	degree_abbr		NVARCHAR(20),
	CONSTRAINT PK_program PRIMARY KEY (program_code)
);


CREATE TABLE Courses (
	program_code	CHAR(4),
	course_code		CHAR(7),
    course_name		NVARCHAR(50),
    semester		INT,
    course_area		CHAR(4),
    type_code		CHAR(4),
    CONSTRAINT PK_courses PRIMARY KEY (course_code),
	CONSTRAINT FK_coursearea FOREIGN KEY (course_area) REFERENCES Areas(course_area),
    CONSTRAINT FK_coursetype FOREIGN KEY (type_code) REFERENCES CourseTypes(type_code)
);


CREATE TABLE Assignments (
	course_code		CHAR(7),
    sec				INT,
	hour_lect		INT,
    hour_lab		INT,
    instructorID	INT,
    CONSTRAINT PK_courses PRIMARY KEY (course_code,sec,instructorID),
	CONSTRAINT FK_courseassm FOREIGN KEY (course_code) REFERENCES Courses(course_code),
    CONSTRAINT FK_instructorassm FOREIGN KEY (instructorID) REFERENCES Instructors(instructorID)
);

